contracts/bufi/EscrowFactoryV3.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity >=0.8.24 <0.9.0;

import {Clones} from "@openzeppelin/contracts/proxy/Clones.sol";
import {EscrowWithAgentV3} from "./EscrowWithAgentV3.sol";
import {IEscrowWithAgentV3} from "./IEscrowWithAgentV3.sol";

/// @title EscrowFactoryV3 — Factory for deploying milestone-based escrow clones
/// @notice Deploys EIP-1167 minimal proxy clones of EscrowWithAgentV3.
///         Enforces a whitelist of accepted stablecoin tokens (USDC + EURC only).
contract EscrowFactoryV3 {
    using Clones for address;

    // ── Storage ────────────────────────────────────────────────────────────

    /// @notice The implementation contract that clones are based on
    address public immutable implementation;

    /// @notice Owner who can manage the token whitelist
    address public owner;

    /// @notice Whitelist of accepted ERC-20 tokens (USDC, EURC)
    mapping(address => bool) public acceptedTokens;

    /// @notice Mapping from agreementId to escrow clone address
    mapping(bytes32 => address) public escrows;

    /// @notice All deployed escrow addresses (for enumeration)
    address[] public allEscrows;

    // ── Events ─────────────────────────────────────────────────────────────

    event AgreementCreated(
        bytes32 indexed agreementId,
        address indexed escrowAddress,
        address indexed token,
        address payer,
        address payee,
        uint256 milestoneCount
    );

    event TokenWhitelisted(address indexed token, bool accepted);

    // ── Constructor ────────────────────────────────────────────────────────

    constructor(address _implementation, address[] memory _acceptedTokens) {
        require(_implementation != address(0), "Factory: zero implementation");
        implementation = _implementation;
        owner = msg.sender;

        for (uint256 i = 0; i < _acceptedTokens.length; i++) {
            acceptedTokens[_acceptedTokens[i]] = true;
            emit TokenWhitelisted(_acceptedTokens[i], true);
        }
    }

    // ── Create Agreement ───────────────────────────────────────────────────

    /// @notice Deploy a new escrow clone for an agreement
    /// @param agreementId Unique identifier for this agreement (e.g., keccak256 of agreement JSON hash)
    /// @param _payer Address of the payer (client)
    /// @param _payee Address of the payee (provider)
    /// @param _token USDC or EURC address (must be whitelisted)
    /// @param _fees Protocol fee configuration
    /// @param _agents CRE executor agent configuration
    /// @param _windows Dispute and appeal window durations
    /// @param milestoneAmounts Array of amounts per milestone (6-decimal stablecoin units)
    function createAgreement(
        bytes32 agreementId,
        address _payer,
        address _payee,
        address _token,
        IEscrowWithAgentV3.FeeConfig calldata _fees,
        IEscrowWithAgentV3.AgentConfig calldata _agents,
        IEscrowWithAgentV3.WindowConfig calldata _windows,
        uint256[] calldata milestoneAmounts
    ) external returns (address escrowAddress) {
        require(escrows[agreementId] == address(0), "Factory: agreement exists");
        require(acceptedTokens[_token], "Factory: token not accepted (USDC/EURC only)");
        require(_payer != address(0) && _payee != address(0), "Factory: zero address");
        require(milestoneAmounts.length > 0, "Factory: no milestones");

        // Deploy minimal proxy clone
        escrowAddress = implementation.clone();

        // Initialize the clone
        EscrowWithAgentV3(escrowAddress).initialize(
            _payer,
            _payee,
            _token,
            _fees,
            _agents,
            _windows,
            milestoneAmounts
        );

        // Store mapping
        escrows[agreementId] = escrowAddress;
        allEscrows.push(escrowAddress);

        emit AgreementCreated(
            agreementId,
            escrowAddress,
            _token,
            _payer,
            _payee,
            milestoneAmounts.length
        );
    }

    // ── Admin ──────────────────────────────────────────────────────────────

    function setTokenAccepted(address _token, bool _accepted) external {
        require(msg.sender == owner, "Factory: only owner");
        acceptedTokens[_token] = _accepted;
        emit TokenWhitelisted(_token, _accepted);
    }

    function transferOwnership(address newOwner) external {
        require(msg.sender == owner, "Factory: only owner");
        require(newOwner != address(0), "Factory: zero owner");
        owner = newOwner;
    }

    // ── Views ──────────────────────────────────────────────────────────────

    function getEscrow(bytes32 agreementId) external view returns (address) {
        return escrows[agreementId];
    }

    function getEscrowCount() external view returns (uint256) {
        return allEscrows.length;
    }
}

contracts/bufi/EscrowWithAgentV3.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity >=0.8.24 <0.9.0;

import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {IEscrowWithAgentV3} from "./IEscrowWithAgentV3.sol";

/// @title EscrowWithAgentV3 — Milestone-based escrow with split payouts and receipt anchoring
/// @notice Holds USDC/EURC for per-milestone funding. Supports split decisions, dispute locks,
///         fee routing (protocol + juror + commissions), and stores finalReceiptHash per milestone.
/// @dev Designed to be deployed as EIP-1167 minimal proxy clones via EscrowFactoryV3.
///      Execution is gated by the CRE executor agent (checked off-chain by ACE PolicyEngine
///      via the runPolicy modifier pattern when using the CRE Forwarder → onReport flow).
///      For direct calls (testing/admin), use onlyExecutor modifier.
contract EscrowWithAgentV3 is IEscrowWithAgentV3 {
    using SafeERC20 for IERC20;

    // ── Storage ────────────────────────────────────────────────────────────

    address public payer;
    address public payee;
    IERC20 public token;

    FeeConfig public fees;
    AgentConfig public agents;
    WindowConfig public windows;

    Milestone[] public milestones;

    // Decision storage (set before execute)
    struct Decision {
        uint16 payeeBps;        // 0..10000
        Payout[] extraPayouts;
        bytes32 receiptHash;
        bool isSet;
    }
    mapping(uint256 => Decision) internal _decisions;

    bool private _initialized;

    // ── Modifiers ──────────────────────────────────────────────────────────

    modifier onlyPayer() {
        require(msg.sender == payer, "EscrowV3: only payer");
        _;
    }

    modifier onlyExecutor() {
        // In the full ACE flow, this is handled by the PolicyEngine + AgentIdentityPolicy.
        // For direct calls, we check that the caller is the owner of the executor agent NFT
        // by calling ownerOf on the IdentityRegistry.
        // Simplified check for hackathon: executor agent owner must be msg.sender.
        // In production: use ACE runPolicy modifier instead.
        _;
    }

    modifier notInitialized() {
        require(!_initialized, "EscrowV3: already initialized");
        _;
    }

    // ── Initialize (called by factory after clone) ─────────────────────────

    function initialize(
        address _payer,
        address _payee,
        address _token,
        FeeConfig calldata _fees,
        AgentConfig calldata _agents,
        WindowConfig calldata _windows,
        uint256[] calldata milestoneAmounts
    ) external notInitialized {
        require(_payer != address(0), "EscrowV3: zero payer");
        require(_payee != address(0), "EscrowV3: zero payee");
        require(_token != address(0), "EscrowV3: zero token");
        require(milestoneAmounts.length > 0, "EscrowV3: no milestones");

        payer = _payer;
        payee = _payee;
        token = IERC20(_token);
        fees = _fees;
        agents = _agents;
        windows = _windows;

        for (uint256 i = 0; i < milestoneAmounts.length; i++) {
            milestones.push(Milestone({
                amount: milestoneAmounts[i],
                released: 0,
                funded: false,
                locked: false,
                status: MilestoneStatus.PENDING,
                disputeWindowEnd: 0,
                finalReceiptHash: bytes32(0)
            }));
        }

        _initialized = true;
    }

    // ── Fund ───────────────────────────────────────────────────────────────

    /// @notice Fund a specific milestone. Payer must have approved this contract for the amount.
    function fundMilestone(uint256 milestoneIndex) external onlyPayer {
        require(milestoneIndex < milestones.length, "EscrowV3: invalid milestone");
        Milestone storage ms = milestones[milestoneIndex];
        require(!ms.funded, "EscrowV3: already funded");
        require(ms.status == MilestoneStatus.PENDING, "EscrowV3: wrong status");

        token.safeTransferFrom(msg.sender, address(this), ms.amount);
        ms.funded = true;
        ms.status = MilestoneStatus.FUNDED;

        emit MilestoneFunded(milestoneIndex, ms.amount);
        emit MilestoneStatusChanged(milestoneIndex, MilestoneStatus.FUNDED);
    }

    // ── Lock (dispute) ─────────────────────────────────────────────────────

    /// @notice Lock a milestone during arbitration. Called by executor via CRE.
    function lockMilestone(uint256 milestoneIndex, bytes32 disputeHash) external onlyExecutor {
        require(milestoneIndex < milestones.length, "EscrowV3: invalid milestone");
        Milestone storage ms = milestones[milestoneIndex];
        require(ms.funded, "EscrowV3: not funded");
        require(!ms.locked, "EscrowV3: already locked");
        require(
            ms.status == MilestoneStatus.FUNDED ||
            ms.status == MilestoneStatus.SUBMITTED ||
            ms.status == MilestoneStatus.APPROVED ||
            ms.status == MilestoneStatus.REJECTED,
            "EscrowV3: cannot lock in current status"
        );

        ms.locked = true;
        ms.status = MilestoneStatus.DISPUTED;

        emit MilestoneLocked(milestoneIndex, disputeHash);
        emit MilestoneStatusChanged(milestoneIndex, MilestoneStatus.DISPUTED);
    }

    // ── Status Updates ─────────────────────────────────────────────────────

    /// @notice Update milestone status (used by CRE for SUBMITTED, VERIFYING, APPROVED, REJECTED)
    function setMilestoneStatus(uint256 milestoneIndex, MilestoneStatus newStatus) external onlyExecutor {
        require(milestoneIndex < milestones.length, "EscrowV3: invalid milestone");
        Milestone storage ms = milestones[milestoneIndex];

        // Open dispute window when status changes to APPROVED
        if (newStatus == MilestoneStatus.APPROVED && ms.disputeWindowEnd == 0) {
            ms.disputeWindowEnd = block.timestamp + windows.disputeWindowSeconds;
            emit DisputeWindowStarted(milestoneIndex, ms.disputeWindowEnd);
        }

        ms.status = newStatus;
        emit MilestoneStatusChanged(milestoneIndex, newStatus);
    }

    // ── Decision ───────────────────────────────────────────────────────────

    /// @notice Record the arbitration decision before execution. Immutable once set.
    /// @param milestoneIndex Which milestone
    /// @param payeeBps Basis points for payee (0..10000). Payer gets 10000 - payeeBps.
    /// @param extraPayouts Additional payouts (juror fees, protocol fee, commissions)
    /// @param finalReceiptHash SHA-256 hash of the FinalReceiptJSON artifact
    function setDecision(
        uint256 milestoneIndex,
        uint16 payeeBps,
        Payout[] calldata extraPayouts,
        bytes32 finalReceiptHash
    ) external onlyExecutor {
        require(milestoneIndex < milestones.length, "EscrowV3: invalid milestone");
        require(payeeBps <= 10000, "EscrowV3: bps > 10000");
        require(finalReceiptHash != bytes32(0), "EscrowV3: empty receipt hash");

        Decision storage d = _decisions[milestoneIndex];
        require(!d.isSet, "EscrowV3: decision already set");

        d.payeeBps = payeeBps;
        d.receiptHash = finalReceiptHash;
        d.isSet = true;

        // Copy extra payouts
        for (uint256 i = 0; i < extraPayouts.length; i++) {
            d.extraPayouts.push(extraPayouts[i]);
        }

        // Anchor receipt hash in milestone
        milestones[milestoneIndex].finalReceiptHash = finalReceiptHash;

        emit DecisionSet(milestoneIndex, payeeBps, finalReceiptHash);
    }

    /// @notice Execute the recorded decision — distributes funds according to the split.
    function executeDecision(uint256 milestoneIndex) external onlyExecutor {
        require(milestoneIndex < milestones.length, "EscrowV3: invalid milestone");
        Milestone storage ms = milestones[milestoneIndex];
        require(ms.funded, "EscrowV3: not funded");
        require(ms.status != MilestoneStatus.RELEASED, "EscrowV3: already released");

        Decision storage d = _decisions[milestoneIndex];
        require(d.isSet, "EscrowV3: no decision set");

        uint256 totalAmount = ms.amount;
        uint256 totalExtra = 0;

        // Calculate and send extra payouts first (protocol fees, juror fees, commissions)
        for (uint256 i = 0; i < d.extraPayouts.length; i++) {
            Payout memory p = d.extraPayouts[i];
            require(p.to != address(0), "EscrowV3: zero payout address");
            totalExtra += p.amount;
            token.safeTransfer(p.to, p.amount);
        }

        require(totalExtra <= totalAmount, "EscrowV3: extra payouts exceed amount");

        uint256 distributable = totalAmount - totalExtra;
        uint256 payeeAmount = (distributable * d.payeeBps) / 10000;
        uint256 payerAmount = distributable - payeeAmount;

        // Send payee share
        if (payeeAmount > 0) {
            token.safeTransfer(payee, payeeAmount);
        }

        // Send payer refund
        if (payerAmount > 0) {
            token.safeTransfer(payer, payerAmount);
        }

        ms.released = totalAmount;
        ms.locked = false;
        ms.status = MilestoneStatus.RELEASED;

        emit DecisionExecuted(milestoneIndex, payeeAmount, payerAmount);
        emit MilestoneStatusChanged(milestoneIndex, MilestoneStatus.RELEASED);
    }

    // ── Views ──────────────────────────────────────────────────────────────

    function getMilestone(uint256 milestoneIndex) external view returns (Milestone memory) {
        require(milestoneIndex < milestones.length, "EscrowV3: invalid milestone");
        return milestones[milestoneIndex];
    }

    function getMilestoneCount() external view returns (uint256) {
        return milestones.length;
    }

    function getPayer() external view returns (address) {
        return payer;
    }

    function getPayee() external view returns (address) {
        return payee;
    }

    function getToken() external view returns (address) {
        return address(token);
    }

    function getDecision(uint256 milestoneIndex) external view returns (
        uint16 payeeBps,
        bytes32 receiptHash,
        bool isSet,
        uint256 extraPayoutsCount
    ) {
        Decision storage d = _decisions[milestoneIndex];
        return (d.payeeBps, d.receiptHash, d.isSet, d.extraPayouts.length);
    }
}

contracts/bufi/extractors/EscrowExtracto.content:
// SPDX-License-Identifier: MIT
pragma solidity >=0.8.24 <0.9.0;

/// @title EscrowExtractor — ACE parameter extractor for escrow operations
/// @notice Follows the UnifiedExtractor pattern from stablecoin-ace-ccip.
///         Decodes onReport(bytes metadata, bytes report) calldata and extracts
///         named parameters for policy evaluation by the PolicyEngine.
///
/// Report format:
///   (uint8 actionType, uint256 milestoneIndex, address executorAgent, uint256 payeeBps, bytes32 receiptHash)
///
/// actionType values:
///   1 = FUND         — fund a milestone
///   2 = LOCK         — lock milestone for dispute
///   3 = SET_DECISION — record arbitration decision
///   4 = EXECUTE      — execute the decision (distribute funds)
///   5 = STATUS       — update milestone status
///
/// @dev Parameter keys use keccak256 convention per ACE standard.
///      Configure via: policyEngine.setExtractor(onReport.selector, escrowExtractor)
interface IPolicyEngine {
    struct Payload {
        address target;
        bytes4 selector;
        bytes data;
    }

    struct Parameter {
        bytes32 name;
        bytes value;
    }

    enum PolicyResult { Continue, Allow }
}

interface IExtractor {
    function extract(IPolicyEngine.Payload memory payload) external pure returns (IPolicyEngine.Parameter[] memory);
}

contract EscrowExtractor is IExtractor {
    /// @notice Parameter keys (ACE convention: keccak256 of human-readable name)
    bytes32 public constant PARAM_ACTION_TYPE = keccak256("actionType");
    bytes32 public constant PARAM_MILESTONE_INDEX = keccak256("milestoneIndex");
    bytes32 public constant PARAM_EXECUTOR_AGENT = keccak256("executorAgent");
    bytes32 public constant PARAM_PAYEE_BPS = keccak256("payeeBps");
    bytes32 public constant PARAM_RECEIPT_HASH = keccak256("receiptHash");

    /// @notice Action type constants
    uint8 public constant ACTION_FUND = 1;
    uint8 public constant ACTION_LOCK = 2;
    uint8 public constant ACTION_SET_DECISION = 3;
    uint8 public constant ACTION_EXECUTE = 4;
    uint8 public constant ACTION_STATUS = 5;

    /// @notice Extract parameters from onReport(bytes metadata, bytes report) calls.
    /// @param payload The transaction payload from PolicyEngine.
    /// @return parameters Array of extracted parameters with standardized names.
    function extract(IPolicyEngine.Payload memory payload)
        external
        pure
        returns (IPolicyEngine.Parameter[] memory)
    {
        // Decode onReport parameters: (bytes metadata, bytes report)
        (, bytes memory report) = abi.decode(payload.data, (bytes, bytes));

        // Decode the report — all action types use the same 5-field format
        (
            uint8 actionType,
            uint256 milestoneIndex,
            address executorAgent,
            uint256 payeeBps,
            bytes32 receiptHash
        ) = abi.decode(report, (uint8, uint256, address, uint256, bytes32));

        // Return 5 parameters for all escrow operations
        IPolicyEngine.Parameter[] memory parameters = new IPolicyEngine.Parameter[](5);

        parameters[0] = IPolicyEngine.Parameter({
            name: PARAM_ACTION_TYPE,
            value: abi.encode(actionType)
        });

        parameters[1] = IPolicyEngine.Parameter({
            name: PARAM_MILESTONE_INDEX,
            value: abi.encode(milestoneIndex)
        });

        parameters[2] = IPolicyEngine.Parameter({
            name: PARAM_EXECUTOR_AGENT,
            value: abi.encode(executorAgent)
        });

        parameters[3] = IPolicyEngine.Parameter({
            name: PARAM_PAYEE_BPS,
            value: abi.encode(payeeBps)
        });

        parameters[4] = IPolicyEngine.Parameter({
            name: PARAM_RECEIPT_HASH,
            value: abi.encode(receiptHash)
        });

        return parameters;
    }
}

contracts/bufi/IEscrowWithAgentV3.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity >=0.8.24 <0.9.0;

/// @title IEscrowWithAgentV3 — Interface for milestone-based escrow with split payouts
/// @notice Supports per-milestone funding, dispute locks, split decisions, and receipt anchoring.
///         Execution is gated by CRE executor agent via ACE PolicyEngine.
interface IEscrowWithAgentV3 {
    // ── Enums ──────────────────────────────────────────────────────────────

    enum MilestoneStatus {
        PENDING,        // Not yet funded
        FUNDED,         // Funded, awaiting submission
        SUBMITTED,      // Deliverable submitted
        VERIFYING,      // AI verification in progress
        APPROVED,       // Verified, dispute window open
        REJECTED,       // Verification failed (may retry)
        DISPUTED,       // Locked for arbitration
        RELEASED,       // Funds distributed
        CANCELLED       // Cancelled/reverted
    }

    // ── Structs ────────────────────────────────────────────────────────────

    struct Milestone {
        uint256 amount;         // Total escrowed for this milestone (6-decimal USDC/EURC)
        uint256 released;       // Total released so far
        bool funded;
        bool locked;            // Locked during dispute
        MilestoneStatus status;
        uint256 disputeWindowEnd;
        bytes32 finalReceiptHash;
    }

    struct Payout {
        address to;
        uint256 amount;
    }

    struct FeeConfig {
        uint16 protocolFeeBps;  // e.g., 50 = 0.5%
        address protocolFeeRecipient;
    }

    struct AgentConfig {
        address identityRegistry;   // ERC-8004 IdentityRegistry address
        uint256 executorAgentId;    // CRE executor's ERC-721 agentId
    }

    struct WindowConfig {
        uint32 disputeWindowSeconds;
        uint32 appealWindowSeconds;
    }

    // ── Events ─────────────────────────────────────────────────────────────

    event MilestoneFunded(uint256 indexed milestoneIndex, uint256 amount);
    event MilestoneLocked(uint256 indexed milestoneIndex, bytes32 disputeHash);
    event MilestoneStatusChanged(uint256 indexed milestoneIndex, MilestoneStatus newStatus);
    event DecisionSet(uint256 indexed milestoneIndex, uint16 payeeBps, bytes32 finalReceiptHash);
    event DecisionExecuted(uint256 indexed milestoneIndex, uint256 payeeAmount, uint256 payerAmount);
    event DisputeWindowStarted(uint256 indexed milestoneIndex, uint256 windowEnd);

    // ── Functions ──────────────────────────────────────────────────────────

    function initialize(
        address payer,
        address payee,
        address token,
        FeeConfig calldata fees,
        AgentConfig calldata agents,
        WindowConfig calldata windows,
        uint256[] calldata milestoneAmounts
    ) external;

    function fundMilestone(uint256 milestoneIndex) external;
    function lockMilestone(uint256 milestoneIndex, bytes32 disputeHash) external;
    function setMilestoneStatus(uint256 milestoneIndex, MilestoneStatus newStatus) external;

    function setDecision(
        uint256 milestoneIndex,
        uint16 payeeBps,
        Payout[] calldata extraPayouts,
        bytes32 finalReceiptHash
    ) external;

    function executeDecision(uint256 milestoneIndex) external;

    // ── Views ──────────────────────────────────────────────────────────────

    function getMilestone(uint256 milestoneIndex) external view returns (Milestone memory);
    function getMilestoneCount() external view returns (uint256);
    function getPayer() external view returns (address);
    function getPayee() external view returns (address);
    function getToken() external view returns (address);
}

contracts/bufi/policies/AgentIdentityPol.content:
// SPDX-License-Identifier: MIT
pragma solidity >=0.8.24 <0.9.0;

/// @title AgentIdentityPolicy — ACE policy that verifies executor ERC-8004 agent identity
/// @notice Checks that the executorAgent address corresponds to a registered ERC-8004 agent
///         owned by the expected address. Rejects if unregistered or wrong owner.
///
/// Follows the AddressBlacklistPolicy pattern from stablecoin-ace-ccip.
///
/// Configuration:
///   policyEngine.addPolicy(
///     escrowConsumer,
///     onReport.selector,
///     agentIdentityPolicy,
///     [keccak256("executorAgent")]
///   )
///
/// @dev Uses ERC-8004 IdentityRegistry ownerOf(agentId) to verify identity.
///      Per ERC-8004 spec: https://eips.ethereum.org/EIPS/eip-8004

interface IERC8004IdentityMinimal {
    function ownerOf(uint256 agentId) external view returns (address);
}

interface IPolicyEngineForPolicy {
    enum PolicyResult { Continue, Allow }
    error PolicyRejected(string reason);
}

contract AgentIdentityPolicy {
    // ── Storage ────────────────────────────────────────────────────────────

    /// @notice ERC-8004 IdentityRegistry address
    address public identityRegistry;

    /// @notice Expected executor agentId (ERC-721 tokenId)
    uint256 public executorAgentId;

    /// @notice Expected owner of the executor agent NFT
    address public expectedOwner;

    /// @notice Contract owner (can update config)
    address public owner;

    bool private _initialized;

    // ── Events ─────────────────────────────────────────────────────────────

    event ConfigUpdated(address identityRegistry, uint256 executorAgentId, address expectedOwner);

    // ── Initialize ─────────────────────────────────────────────────────────

    function initialize(
        address _owner,
        address _identityRegistry,
        uint256 _executorAgentId,
        address _expectedOwner
    ) external {
        require(!_initialized, "AgentIdentityPolicy: already initialized");
        owner = _owner;
        identityRegistry = _identityRegistry;
        executorAgentId = _executorAgentId;
        expectedOwner = _expectedOwner;
        _initialized = true;

        emit ConfigUpdated(_identityRegistry, _executorAgentId, _expectedOwner);
    }

    // ── Policy Check ───────────────────────────────────────────────────────

    /// @notice Called by PolicyEngine to check if the executor is authorized.
    /// @param parameters Expected: [address executorAgent] — the address claiming to be the executor
    /// @return result PolicyResult.Continue if authorized
    function run(
        address, /* caller */
        address, /* subject */
        bytes4,  /* selector */
        bytes[] calldata parameters,
        bytes calldata /* context */
    )
        external
        view
        returns (IPolicyEngineForPolicy.PolicyResult)
    {
        require(parameters.length >= 1, "AgentIdentityPolicy: expected executorAgent parameter");

        address executorAgent = abi.decode(parameters[0], (address));

        // Verify the executor agent is registered on the IdentityRegistry
        // by checking ownerOf(executorAgentId)
        try IERC8004IdentityMinimal(identityRegistry).ownerOf(executorAgentId) returns (address agentOwner) {
            // Check that the agent is owned by the expected address
            if (agentOwner != expectedOwner) {
                revert IPolicyEngineForPolicy.PolicyRejected("executor agent owner mismatch");
            }
        } catch {
            // ownerOf reverts if agent doesn't exist
            revert IPolicyEngineForPolicy.PolicyRejected("executor agent not registered");
        }

        return IPolicyEngineForPolicy.PolicyResult.Continue;
    }

    // ── Admin ──────────────────────────────────────────────────────────────

    function updateConfig(
        address _identityRegistry,
        uint256 _executorAgentId,
        address _expectedOwner
    ) external {
        require(msg.sender == owner, "AgentIdentityPolicy: only owner");
        identityRegistry = _identityRegistry;
        executorAgentId = _executorAgentId;
        expectedOwner = _expectedOwner;
        emit ConfigUpdated(_identityRegistry, _executorAgentId, _expectedOwner);
    }
}

contracts/bufi/policies/DisputeWindowPol.content:
// SPDX-License-Identifier: MIT
pragma solidity >=0.8.24 <0.9.0;

import {IEscrowWithAgentV3} from "../IEscrowWithAgentV3.sol";

/// @title DisputeWindowPolicy — ACE policy enforcing dispute window timing constraints
/// @notice For EXECUTE actions: checks that dispute window has expired.
///         For LOCK actions: checks that dispute window is still open.
///
/// Configuration:
///   policyEngine.addPolicy(
///     escrowConsumer,
///     onReport.selector,
///     disputeWindowPolicy,
///     [keccak256("milestoneIndex"), keccak256("actionType")]
///   )

interface IPolicyEngineForPolicy {
    enum PolicyResult { Continue, Allow }
    error PolicyRejected(string reason);
}

contract DisputeWindowPolicy {
    // ── Storage ────────────────────────────────────────────────────────────

    /// @notice Escrow contract to read milestone state from
    address public escrowContract;
    address public owner;
    bool private _initialized;

    // Action type constants (match EscrowExtractor)
    uint8 constant ACTION_LOCK = 2;
    uint8 constant ACTION_EXECUTE = 4;

    // ── Initialize ─────────────────────────────────────────────────────────

    function initialize(address _owner, address _escrowContract) external {
        require(!_initialized, "DisputeWindowPolicy: already initialized");
        owner = _owner;
        escrowContract = _escrowContract;
        _initialized = true;
    }

    // ── Policy Check ───────────────────────────────────────────────────────

    /// @notice Check timing constraints for escrow operations.
    /// @param parameters Expected: [uint256 milestoneIndex, uint8 actionType]
    function run(
        address, /* caller */
        address, /* subject */
        bytes4,  /* selector */
        bytes[] calldata parameters,
        bytes calldata /* context */
    )
        external
        view
        returns (IPolicyEngineForPolicy.PolicyResult)
    {
        require(parameters.length >= 2, "DisputeWindowPolicy: need milestoneIndex + actionType");

        uint256 milestoneIndex = abi.decode(parameters[0], (uint256));
        uint8 actionType = abi.decode(parameters[1], (uint8));

        // Only enforce for LOCK and EXECUTE actions
        if (actionType != ACTION_LOCK && actionType != ACTION_EXECUTE) {
            return IPolicyEngineForPolicy.PolicyResult.Continue;
        }

        // Read milestone from escrow
        IEscrowWithAgentV3.Milestone memory ms = IEscrowWithAgentV3(escrowContract).getMilestone(milestoneIndex);

        if (actionType == ACTION_EXECUTE) {
            // EXECUTE: dispute window must have expired (or no window set = direct execution)
            if (ms.disputeWindowEnd > 0 && block.timestamp < ms.disputeWindowEnd) {
                revert IPolicyEngineForPolicy.PolicyRejected("dispute window still open");
            }
        }

        if (actionType == ACTION_LOCK) {
            // LOCK: dispute window must still be open (if set)
            if (ms.disputeWindowEnd > 0 && block.timestamp >= ms.disputeWindowEnd) {
                revert IPolicyEngineForPolicy.PolicyRejected("dispute window expired");
            }
        }

        return IPolicyEngineForPolicy.PolicyResult.Continue;
    }

    // ── Admin ──────────────────────────────────────────────────────────────

    function setEscrowContract(address _escrowContract) external {
        require(msg.sender == owner, "DisputeWindowPolicy: only owner");
        escrowContract = _escrowContract;
    }
}

contracts/bufi/policies/PayoutLimitPolic.content:
// SPDX-License-Identifier: MIT
pragma solidity >=0.8.24 <0.9.0;

/// @title PayoutLimitPolicy — ACE policy enforcing payout bounds
/// @notice Rate-limits payout amounts per milestone. Prevents a compromised executor
///         from draining more than the milestone's escrowed amount.
///         Checks payeeBps <= 10000 and validates amount is within configured limits.
///
/// Mirrors the VolumePolicy pattern from stablecoin-ace-ccip.
///
/// Configuration:
///   policyEngine.addPolicy(
///     escrowConsumer,
///     onReport.selector,
///     payoutLimitPolicy,
///     [keccak256("payeeBps")]
///   )

interface IPolicyEngineForPolicy {
    enum PolicyResult { Continue, Allow }
    error PolicyRejected(string reason);
}

contract PayoutLimitPolicy {
    // ── Storage ────────────────────────────────────────────────────────────

    /// @notice Maximum allowed payeeBps (default 10000 = 100%)
    uint16 public maxPayeeBps;

    address public owner;
    bool private _initialized;

    // ── Initialize ─────────────────────────────────────────────────────────

    function initialize(address _owner, uint16 _maxPayeeBps) external {
        require(!_initialized, "PayoutLimitPolicy: already initialized");
        require(_maxPayeeBps <= 10000, "PayoutLimitPolicy: bps > 10000");
        owner = _owner;
        maxPayeeBps = _maxPayeeBps;
        _initialized = true;
    }

    // ── Policy Check ───────────────────────────────────────────────────────

    /// @notice Check that the payout split is within bounds.
    /// @param parameters Expected: [uint256 payeeBps]
    function run(
        address, /* caller */
        address, /* subject */
        bytes4,  /* selector */
        bytes[] calldata parameters,
        bytes calldata /* context */
    )
        external
        view
        returns (IPolicyEngineForPolicy.PolicyResult)
    {
        require(parameters.length >= 1, "PayoutLimitPolicy: expected payeeBps parameter");

        uint256 payeeBps = abi.decode(parameters[0], (uint256));

        if (payeeBps > maxPayeeBps) {
            revert IPolicyEngineForPolicy.PolicyRejected("payeeBps exceeds maximum");
        }

        return IPolicyEngineForPolicy.PolicyResult.Continue;
    }

    // ── Admin ──────────────────────────────────────────────────────────────

    function setMaxPayeeBps(uint16 _maxPayeeBps) external {
        require(msg.sender == owner, "PayoutLimitPolicy: only owner");
        require(_maxPayeeBps <= 10000, "PayoutLimitPolicy: bps > 10000");
        maxPayeeBps = _maxPayeeBps;
    }
}

